class Solution:
    def maximumSumQueries(self, nums1: List[int], nums2: List[int], queries: List[List[int]]) -> List[int]:
        import bisect

        n = len(nums1)
        pairs = sorted([(nums1[i], nums2[i]) for i in range(n)], key=lambda x: (x[0], x[1]))
        max_sums = []
        res = []

        for x, y in queries:
            idx = bisect.bisect_left(pairs, (x, y))
            max_sum = -1
            for i in range(idx, len(pairs)):
                if pairs[i][0] >= x and pairs[i][1] >= y:
                    max_sum = max(max_sum, pairs[i][0] + pairs[i][1])
            res.append(max_sum)

        return res
